#!/usr/bin/env perl

use strict;
use warnings;
use DBI;

my $username = param('username');
my $password = param('password');

my $dsn = "DBI:mysql:database=mydatabase;host=localhost";
my $dbh = DBI->connect($dsn, 'username', 'password') or die "Connection failed: $!";

my $query = "SELECT * FROM users WHERE username='$username' AND password='$password'";
my $sth = $dbh->prepare($query);
$sth->execute();

while (my $row = $sth->fetchrow_hashref()) {
    print $row->{username} . "\n";
}

$sth->finish();
$dbh->disconnect();